   143→    if (activeProject) {
   144→      setIsLoadingFeatures(true);
   145→      // First ensure harness is initialized, then fetch features
   146→      initializeHarnessIfNeeded(activeProject.path)
   147→        .then((initialized) => {
   148→          if (initialized) {
   149→            return fetchProjectFeatures(activeProject.path);
   150→          }
   151→          return [];
   152→        })
   153→        .then(setFeatures)
   154→        .finally(() => setIsLoadingFeatures(false));
   155→    } else {
   156→      setFeatures([]);
   157→    }
   158→  }, [activeProjectId, projects]);
   159→
   160→  // Listen for menu events
   161→  useEffect(() => {
   162→    const listeners = [
   163→      listen('menu:open_project', () => {
   164→        setIsProjectSelectorOpen(true);
   165→      }),
   166→      listen('menu:new_tab', () => {
   167→        handleAddProject();
   168→      }),
   169→      listen('menu:close_tab', () => {
   170→        if (activeProjectId) {
   171→          handleCloseProject(activeProjectId);
   172→        }
   173→      }),
   174→      listen('menu:settings', () => {
   175→        setIsSettingsOpen(true);
   176→      }),
   177→    ];
   178→
   179→    return () => {
   180→      listeners.forEach(async (unlistenPromise) => {
   181→        const unlisten = await unlistenPromise;
   182→        unlisten();
   183→      });
   184→    };
   185→  }, [activeProjectId]);
