   316→      args.push('--title', taskData.title);
   317→    }
   318→    if (taskData.description) {
   319→      args.push('--description', taskData.description);
   320→    }
   321→    args.push('--status', taskData.status.toLowerCase());
   322→    if (taskData.category) {
   323→      args.push('--category', taskData.category);
   324→    }
