   433→
   434→      {/* Project Content - only show when there's an active project */}
   435→      {activeProject && (
   436→        <>
   437→          <PageSection>
   438→            <Card>
   439→              <CardTitle>{activeProject.name}</CardTitle>
   440→              <CardBody>
