   531→        onClose={() => setIsSettingsOpen(false)}
   532→        onSettingsChange={setSettings}
   533→      />
   534→
   535→      {/* Task Modal */}
   536→      <TaskModal
   537→        isOpen={isTaskModalOpen}
   538→        onClose={handleCloseTaskModal}
   539→        onSave={handleSaveTask}
   540→        task={editingTask}
   541→      />
   542→    </Page>
   543→  );
   544→}
   545→
   546→export default App;
