/**
 * Dev Bridge RPC Client
 *
 * Provides a unified API that works in both Tauri (native) and browser contexts.
 * In Tauri: Uses native invoke()
 * In Browser: Uses WebSocket connection to dev bridge server
 */

// Types matching Rust definitions
export interface ProcessInfo {
  id: string;
  cmd: string;
  cwd: string;
  rows: number;
  cols: number;
  running: boolean;
}

export interface RpcRequest {
  id: string;
  cmd: string;
  args: Record<string, unknown>;
}

export interface RpcResponse {
  id: string;
  success: boolean;
  result?: unknown;
  error?: string;
}

export interface RpcEvent {
  event: string;
  payload: unknown;
}

export interface PtyOutput {
  id: string;
  data: string;
}

export interface PtyExit {
  id: string;
  code: number | null;
}

// Check if running in Tauri context
export function isTauri(): boolean {
  return typeof window !== "undefined" && "__TAURI__" in window;
}

// Dev Bridge connection state
let ws: WebSocket | null = null;
let token: string | null = null;
let pendingRequests: Map<
  string,
  { resolve: (value: unknown) => void; reject: (error: Error) => void }
> = new Map();
let eventHandlers: Map<string, Set<(payload: unknown) => void>> = new Map();
let reconnectAttempts = 0;
const MAX_RECONNECT_ATTEMPTS = 5;
const DEV_BRIDGE_PORT = 9876;

/**
 * Generate unique request ID
 */
function generateId(): string {
  return `${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;
}

/**
 * Get token from temp file or environment
 * In development, the Rust server writes token to temp dir
 */
async function getToken(): Promise<string | null> {
  if (token) return token;

  // Try to fetch token from dev server endpoint
  try {
    const response = await fetch(
      `http://127.0.0.1:${DEV_BRIDGE_PORT}/health`
    );
    if (response.ok) {
      // Token is passed via URL parameter, we need to get it from somewhere
      // For now, try localStorage or prompt
      const storedToken = localStorage.getItem("hq-dev-bridge-token");
      if (storedToken) {
        token = storedToken;
        return token;
      }
    }
  } catch {
    // Server not running
  }

  return null;
}

/**
 * Connect to dev bridge WebSocket server
 */
async function connectDevBridge(): Promise<boolean> {
  if (ws && ws.readyState === WebSocket.OPEN) {
    return true;
  }

  const authToken = await getToken();
  if (!authToken) {
    console.warn(
      "[DevBridge] No token available. Set localStorage 'hq-dev-bridge-token' with the token shown in terminal."
    );
    return false;
  }

  return new Promise((resolve) => {
    try {
      ws = new WebSocket(
        `ws://127.0.0.1:${DEV_BRIDGE_PORT}/ws?token=${authToken}`
      );

      ws.onopen = () => {
        console.log("[DevBridge] Connected");
        reconnectAttempts = 0;
        resolve(true);
      };

      ws.onclose = () => {
        console.log("[DevBridge] Disconnected");
        ws = null;

        // Reject all pending requests
        pendingRequests.forEach(({ reject }) => {
          reject(new Error("Connection closed"));
        });
        pendingRequests.clear();

        // Attempt reconnection
        if (reconnectAttempts < MAX_RECONNECT_ATTEMPTS) {
          reconnectAttempts++;
          setTimeout(() => connectDevBridge(), 1000 * reconnectAttempts);
        }

        resolve(false);
      };

      ws.onerror = (error) => {
        console.error("[DevBridge] Error:", error);
        resolve(false);
      };

      ws.onmessage = (event) => {
        try {
          const data = JSON.parse(event.data) as RpcEvent;

          if (data.event === "rpc-response") {
            const response = data.payload as RpcResponse;
            const pending = pendingRequests.get(response.id);
            if (pending) {
              pendingRequests.delete(response.id);
              if (response.success) {
                pending.resolve(response.result);
              } else {
                pending.reject(new Error(response.error || "Unknown error"));
              }
            }
          } else {
            // Emit event to handlers
            const handlers = eventHandlers.get(data.event);
            if (handlers) {
              handlers.forEach((handler) => handler(data.payload));
            }

            // Also emit to wildcard handlers
            const wildcardHandlers = eventHandlers.get("*");
            if (wildcardHandlers) {
              wildcardHandlers.forEach((handler) => handler(data));
            }
          }
        } catch (e) {
          console.error("[DevBridge] Failed to parse message:", e);
        }
      };
    } catch (e) {
      console.error("[DevBridge] Failed to connect:", e);
      resolve(false);
    }
  });
}

/**
 * Check if dev bridge is available
 */
export async function isDevBridgeAvailable(): Promise<boolean> {
  if (isTauri()) return false;

  try {
    const response = await fetch(
      `http://127.0.0.1:${DEV_BRIDGE_PORT}/health`,
      { signal: AbortSignal.timeout(1000) }
    );
    return response.ok;
  } catch {
    return false;
  }
}

/**
 * Set the dev bridge token
 */
export function setDevBridgeToken(newToken: string): void {
  token = newToken;
  localStorage.setItem("hq-dev-bridge-token", newToken);
}

/**
 * Unified invoke function - works in Tauri and browser contexts
 */
export async function invoke<T>(
  cmd: string,
  args: Record<string, unknown> = {}
): Promise<T> {
  // Tauri native context
  if (isTauri()) {
    const { invoke: tauriInvoke } = await import("@tauri-apps/api/core");
    return tauriInvoke<T>(cmd, args);
  }

  // Browser context - use dev bridge
  const connected = await connectDevBridge();
  if (!connected || !ws) {
    throw new Error(
      "Dev bridge not available. Make sure the app is running with 'bun tauri dev' and token is set."
    );
  }

  const id = generateId();
  const request: RpcRequest = { id, cmd, args };

  return new Promise((resolve, reject) => {
    pendingRequests.set(id, {
      resolve: resolve as (value: unknown) => void,
      reject,
    });

    ws!.send(JSON.stringify(request));

    // Timeout after 30 seconds
    setTimeout(() => {
      if (pendingRequests.has(id)) {
        pendingRequests.delete(id);
        reject(new Error(`Request timeout: ${cmd}`));
      }
    }, 30000);
  });
}

/**
 * Listen for events from backend
 */
export async function listen<T>(
  event: string,
  handler: (payload: T) => void
): Promise<() => void> {
  // Tauri native context
  if (isTauri()) {
    const { listen: tauriListen } = await import("@tauri-apps/api/event");
    const unlisten = await tauriListen<T>(event, (e) => handler(e.payload));
    return unlisten;
  }

  // Browser context - use dev bridge event handlers
  if (!eventHandlers.has(event)) {
    eventHandlers.set(event, new Set());
  }
  eventHandlers.get(event)!.add(handler as (payload: unknown) => void);

  // Connect if not already
  await connectDevBridge();

  // Return unlisten function
  return () => {
    const handlers = eventHandlers.get(event);
    if (handlers) {
      handlers.delete(handler as (payload: unknown) => void);
    }
  };
}

// ============================================
// PTY Commands (convenience wrappers)
// ============================================

export async function ptySpawn(
  cmd: string,
  args: string[] = [],
  cwd: string = ".",
  rows: number = 24,
  cols: number = 80
): Promise<ProcessInfo> {
  return invoke<ProcessInfo>("pty_spawn", { cmd, args, cwd, rows, cols });
}

export async function ptyWrite(id: string, data: string): Promise<void> {
  return invoke<void>("pty_write", { id, data });
}

export async function ptyResize(
  id: string,
  rows: number,
  cols: number
): Promise<void> {
  return invoke<void>("pty_resize", { id, rows, cols });
}

export async function ptyKill(id: string): Promise<void> {
  return invoke<void>("pty_kill", { id });
}

export async function ptyList(): Promise<ProcessInfo[]> {
  return invoke<ProcessInfo[]>("pty_list", {});
}

export async function ptyGet(id: string): Promise<ProcessInfo | null> {
  return invoke<ProcessInfo | null>("pty_get", { id });
}

// ============================================
// Event Listeners
// ============================================

export async function onPtyOutput(
  handler: (output: PtyOutput) => void
): Promise<() => void> {
  return listen<PtyOutput>("pty-output", handler);
}

export async function onPtyExit(
  handler: (exit: PtyExit) => void
): Promise<() => void> {
  return listen<PtyExit>("pty-exit", handler);
}

