     1→/**
     2→ * useHarnessWatcher - Hook for watching .harness directory changes (F008)
     3→ *
     4→ * Watches the .harness directory for file changes and triggers
     5→ * a callback when changes are detected. Uses debouncing on the
     6→ * Rust side (500ms) to avoid excessive updates.
     7→ */
     8→
     9→import { useEffect, useCallback, useRef } from 'react';
    10→import { invoke } from '@tauri-apps/api/core';
    11→import { listen, UnlistenFn } from '@tauri-apps/api/event';
    12→
    13→export interface HarnessChangeEvent {
    14→  /** The project path being watched */
    15→  project_path: string;
    16→  /** Type of change: "db", "config", or "unknown" */
    17→  change_type: 'db' | 'config' | 'unknown';
    18→  /** The file that changed (relative to .harness/) */
    19→  file: string;
    20→}
    21→
    22→export interface UseHarnessWatcherOptions {
    23→  /** Project path to watch */
    24→  projectPath: string;
    25→  /** Callback when changes are detected */
    26→  onChange?: (event: HarnessChangeEvent) => void;
    27→  /** Whether to enable watching (default: true) */
    28→  enabled?: boolean;
    29→}
    30→
    31→/**
    32→ * Hook to watch a project's .harness directory for changes
    33→ *
    34→ * @example
    35→ * ```tsx
    36→ * useHarnessWatcher({
    37→ *   projectPath: '/path/to/project',
    38→ *   onChange: (event) => {
    39→ *     console.log('Change detected:', event.file);
    40→ *     refetchData();
    41→ *   },
    42→ * });
    43→ * ```
    44→ */
    45→export function useHarnessWatcher({
    46→  projectPath,
    47→  onChange,
    48→  enabled = true,
    49→}: UseHarnessWatcherOptions): void {
    50→  const isWatchingRef = useRef(false);
    51→  const onChangeRef = useRef(onChange);
    52→
    53→  // Keep onChange ref up to date
    54→  useEffect(() => {
    55→    onChangeRef.current = onChange;
    56→  }, [onChange]);
    57→
    58→  // Check if we're in Tauri context
    59→  const isTauri = useCallback(() => {
    60→    return typeof window !== 'undefined' && '__TAURI__' in window;
    61→  }, []);
    62→
    63→  useEffect(() => {
    64→    if (!enabled || !projectPath || !isTauri()) {
    65→      return;
    66→    }
    67→
    68→    let unlistenFn: UnlistenFn | null = null;
    69→
    70→    const startWatching = async () => {
    71→      try {
    72→        // Start watching
    73→        await invoke('harness_watch_start', { projectPath });
    74→        isWatchingRef.current = true;
    75→
    76→        // Listen for change events
    77→        unlistenFn = await listen<HarnessChangeEvent>('harness-change', (event) => {
    78→          // Only handle events for this project
    79→          if (event.payload.project_path === projectPath) {
    80→            onChangeRef.current?.(event.payload);
    81→          }
    82→        });
    83→      } catch (error) {
    84→        console.error('Failed to start harness watcher:', error);
    85→      }
    86→    };
    87→
    88→    startWatching();
    89→
    90→    return () => {
    91→      // Cleanup: stop watching and remove listener
    92→      if (isWatchingRef.current) {
    93→        invoke('harness_watch_stop', { projectPath }).catch((e) =>
    94→          console.error('Failed to stop harness watcher:', e)
    95→        );
    96→        isWatchingRef.current = false;
    97→      }
    98→      if (unlistenFn) {
    99→        unlistenFn();
   100→      }
   101→    };
   102→  }, [projectPath, enabled, isTauri]);
   103→}
   104→
   105→export default useHarnessWatcher;
