    44→  const time = date.toLocaleTimeString('en-US', {
    45→    hour12: false,
    46→    hour: '2-digit',
    47→    minute: '2-digit',
    48→    second: '2-digit',
    49→  });
    50→  const ms = String(date.getMilliseconds()).padStart(3, '0');
    51→  const timestamp = `${time}.${ms}`;
    52→
    53→  // Color prefix based on log level
    54→  const levelColors: Record<string, string> = {
    55→    error: '\x1b[91m',
    56→    warn: '\x1b[93m',
    57→    info: '\x1b[97m',
    58→    debug: '\x1b[90m',
    59→  };
    60→
    61→  const levelColor = levelColors[entry.level] || '';
    62→  const reset = '\x1b[0m';
    63→
    64→  return `${levelColor}[${timestamp}] [${entry.processName}] ${entry.message}${reset}`;
    65→}
